5: // V2 migrates dashboard from schema version 0 or 1 to 2.
6: // This migration handles the legacy services.filter structure.
7: // It matches the frontend DashboardMigrator.ts logic for oldVersion < 2 && finalTargetVersion >= 2.
8: //
9: // Key migrations:
10: // 1. Services filter migration: old.services.filter.time -> dashboard.time
11: // 2. Services filter migration: old.services.filter.list -> dashboard.templating.list
12: //
13: // Example before migration:
14: //
15: //	{
16: //	  "schemaVersion": 1,
17: //	  "services": {
18: //	    "filter": {
19: //	      "time": {"from": "now-1h", "to": "now"},
20: //	      "list": [{"name": "var1", "type": "query"}]
21: //	    }
22: //	  }
23: //	}
24: //
25: // Example after migration:
26: //
27: //	{
28: //	  "schemaVersion": 2,
29: //	  "time": {"from": "now-1h", "to": "now"},
30: //	  "templating": {
31: //	    "list": [{"name": "var1", "type": "query"}]
32: //	  }
33: //	}
34: func V2(_ context.Context, dashboard map[string]interface{}) error {
35: 	dashboard["schemaVersion"] = 2
36: 
37: 	// Migrate services.filter structure
38: 	migrateServicesFilter(dashboard)
39: 
40: 	return nil
41: }
42: 
43: // migrateServicesFilter migrates the legacy services.filter structure
44: func migrateServicesFilter(dashboard map[string]interface{}) {
45: 	services, ok := dashboard["services"].(map[string]interface{})
46: 	if !ok {
47: 		return
48: 	}
49: 
50: 	filter, ok := services["filter"].(map[string]interface{})
51: 	if !ok {
52: 		return
53: 	}
54: 
55: 	// Migrate time property
56: 	if time, ok := filter["time"]; ok {
57: 		dashboard["time"] = time
58: 	}
59: 
60: 	// Migrate templating list
61: 	if list, ok := filter["list"]; ok {
62: 		if _, exists := dashboard["templating"]; !exists {
63: 			dashboard["templating"] = map[string]interface{}{}
64: 		}
65: 		templating := dashboard["templating"].(map[string]interface{})
66: 		templating["list"] = list
67: 	}
68: 
69: 	// Remove the services property after migration
70: 	delete(dashboard, "services")
71: }
